module div_16bit (
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

    reg [15:0] a_reg;
    reg [7:0] b_reg;
    reg [15:0] remainder;
    reg [4:0] i;

    always @(A, B) begin
        a_reg <= A;
        b_reg <= B;
    end

    always @(a_reg, b_reg) begin
        result = 0;
        remainder = a_reg;
        for (i = 0; i < 16; i = i + 1) begin
            if (remainder[15:8] >= b_reg) begin
                result = {result[14:0], 1'b1};
                remainder = remainder - {1'b0, b_reg, 7'b0};
            end else begin
                result = {result[14:0], 1'b0};
            end
            remainder = {remainder[14:0], a_reg[15-i]};
        end
        odd = remainder;
    end

endmodule
